import { Component, OnInit } from '@angular/core';
import { Router } from '@angular/router';
import { AuthService } from 'src/app/core/services/auth.service';
import { Chart } from 'chart.js/auto';


@Component({
    selector: 'app-dashboard',
    templateUrl: './dashboard.component.html',
    styleUrls: ['./dashboard.component.css'],
})
export class DashboardComponent implements OnInit {
    profile: any;
    constructor(private router: Router, private authService: AuthService) { }

    ngOnInit() {
        this.authService.getProfile().subscribe({
            next: (res: any) => {
                console.log("PROFILE RESPONSE:", res);
                this.profile = res;
            },
            error: (err) => {
                console.log(err);
            }

        });
        this.profile.healthScore = this.calculateHealthScore();

        setTimeout(() => {
            this.createChart();
        }, 200);
    }
    createChart() {
        new Chart("bmiChart", {
            type: 'bar',
            data: {
                labels: ['Your BMI'],
                datasets: [{
                    label: 'BMI',
                    data: [this.profile.bmi]
                }]
            }
        });
    }
    ngAfterViewInit() {
        if (this.profile?.bmi) {
            new Chart("bmiChart", {
                type: 'bar',
                data: {
                    labels: ['Your BMI'],
                    datasets: [{
                        label: 'BMI',
                        data: [this.profile.bmi]
                    }]
                }
            });
        }
    }

    logout() {

        this.authService.logut();
        this.router.navigate(['/login']);
    }

    aiPlan: string = '';
    medicineName: string = '';
    medicineTime: string = '';

    getPlan() {
        this.authService.getAIPlan(this.profile).subscribe({
            next: (res: any) => {
                console.log("AI PLAN RESPONSE:", res);
                this.aiPlan = res;
            },
            error: (err) => {
                console.log("AI ERROR:", err);
                alert("AI Error");
            }
        });
    }

    reminders: { name: string; time: string }[] = [];

    setReminder() {
        if (!this.medicineName || !this.medicineTime) return;

        this.reminders.push({
            name: this.medicineName,
            time: this.medicineTime
        });

        this.medicineName = '';
        this.medicineTime = '';
    }

    deleteReminder(index: number) {
        this.reminders.splice(index, 1);
    }
    calculateHealthScore() {

        if (!this.profile) return 0;

        let score = 0;
        const bmi = this.profile.bmi;
        const diseases = this.profile.knownDiseases || [];

        // BMI score
        if (bmi >= 18.5 && bmi < 25) {
            score = 90;
        } else if (bmi >= 25 && bmi < 30) {
            score = 70;
        } else if (bmi < 18.5) {
            score = 65;
        } else {
            score = 50;
        }

        // Deduct for diseases
        score -= diseases.length * 10;

        if (score < 20) score = 20;

        return score;
    }


}
